-- SIMPLE WORKING UPDATE for branch_id\n-- This is the confirmed working solution\n\n-- Check before\nSELECT 'Before update:' as status, COUNT(*) as subjects_without_branch_id \nFROM subjects WHERE branch_id IS NULL OR branch_id = '';\n\n-- THE WORKING UPDATE QUERY\nUPDATE subjects s\nLEFT JOIN classes c \n  ON s.class_code = c.class_code \n AND s.school_id = c.school_id\nSET s.branch_id = c.branch_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '');\n\n-- Check after\nSELECT 'After update:' as status, COUNT(*) as subjects_still_without_branch_id \nFROM subjects WHERE branch_id IS NULL OR branch_id = '';\n\n-- Show success\nSELECT \n    CASE \n        WHEN COUNT(*) = 0 THEN '🎉 SUCCESS: All subjects now have branch_id!'\n        ELSE CONCAT('✅ PROGRESS: Updated successfully, ', COUNT(*), ' subjects still need manual assignment')\n    END as result\nFROM subjects WHERE branch_id IS NULL OR branch_id = '';\n\n-- Show distribution\nSELECT \n    school_id,\n    branch_id,\n    COUNT(*) as subject_count\nFROM subjects \nWHERE branch_id IS NOT NULL AND branch_id != ''\nGROUP BY school_id, branch_id\nORDER BY school_id, branch_id;\n"